var e=[{id:`L2_1`,type:`dialog`,speaker:`AI_SCHOOL_NULL_NULL`,text:{KOREA:`좌표 입력 확인, 위성 포격 시스템 '굿나잇 키스' 가동.`,JPN:`座標入力確認、衛星砲撃システム「グッドナイト・キス」稼働。`,ENG:`Checking the entered coordinates... Activating the satellite cannonade system, Good Night Kiss...`,TWN:`確認輸入座標，啟動衛星炮擊系統“晚安之吻”。`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHAIR_SCHOOL_SUMMER_NULL`,text:{KOREA:`하하하하! 아하하하핫!! 내 단잠을 깨운 것들을 모두 태워 버려!`,JPN:`ハハハ！　アハハハッ！　私の睡眠の邪魔をしたやつらを燃やし尽くしちまえ～！`,ENG:`Hah hah hah! Mwa hah hah hah! Let them burn! They disturbed my sleep!`,TWN:`哈哈哈哈！啊哈哈哈！！打擾我睡覺的人通通燒毀吧！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`이, 이런! 이대론 전멸이야!`,JPN:`まずい！　このままでは全滅だ！`,ENG:`Oh, no. She's going to wipe us out!`,TWN:`該、該死！這樣下去會全滅的！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_BOSS`,text:{KOREA:`다들, 일단 물러선다! 후퇴!`,JPN:`一旦撤退だ！　全員撤退しろ！`,ENG:`Everyone, go back! Retreat!`,TWN:`所有人暫時撤退！撤退！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`RIFLE_FOX_ENEMY_BOSS`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,text:{KOREA:`적들이 후퇴하고 있네요. 이번에도 저의 멋진 승리인 걸로?`,JPN:`敵が撤退したようですね。今回も僕たちの見事な勝利ということですかね？`,ENG:`They're retreating. It's my victory again!`,TWN:`敵人正在撤退呢，看來這次又是我們的勝利吧？`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`그게 문제가 아니라고 이 여자야!`,JPN:`そんなこと言ってる場合ですか！`,ENG:`Hey, that's not the problem!`,TWN:`問題不在這裡吧，妳這女人！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`이대로 가다간 학교 건물까지 전부 무너지게 생겼잖아!`,JPN:`このままじゃ、学校が焼け野原になっちゃいます！`,ENG:`At this rate, even the school buildings are going to get destroyed!`,TWN:`妳沒看到再這樣下去，整個學校大樓都要倒塌了嗎！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_SUMMER_NULL`,text:{KOREA:`그건 걱정 마세요. 이럴 때를 위해서 제가 옆에 붙어 있는 거니까요.`,JPN:`それは心配ありません。こういう時のために私が傍についているのです。`,ENG:`Don't worry. This is why I'm with her.`,TWN:`不用擔心，我就是為了應付這種時候才會待在她旁邊的。`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`PRESIDENT_SCHOOL_SUMMER_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CHAIR_SCHOOL_SUMMER_NULL`,text:{KOREA:`크하하핫......!`,JPN:`アハハハッ……！`,ENG:`Bwa hah hah hah—`,TWN:`哇哈哈哈……！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`CHAIR_SCHOOL_SUMMER_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CHAIR_SCHOOL_SUMMER_NULL`,text:{KOREA:`에극?!`,JPN:`うっ！`,ENG:`Ack?`,TWN:`呃？！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`CHAIR_SCHOOL_SUMMER_NULL`,face:`UNIT_SURPRISE`},R:{char_id:`PRESIDENT_SCHOOL_SUMMER_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`CHAIR_SCHOOL_SUMMER_NULL`,text:{KOREA:`......쿠울......`,JPN:`……すやぁ……`,ENG:`Zzz...`,TWN:`……呼……`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`CHAIR_SCHOOL_SUMMER_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`우와, 손가락 하나로 사람을 기절시켰어......`,JPN:`うわぁ、指一本で気絶させた……`,ENG:`Whoa, you knocked her out with just a finger!`,TWN:`哇，只用一根手指就把人點暈了……`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,text:{KOREA:`무협지에서나 나오는 기술인 줄 알았는데, 저런 게 실제로 가능한 줄은 몰랐네요.`,JPN:`小説や漫画に出てくる技だとばかり思ってましたけど、あんなものが実在するなんて知りませんでした。`,ENG:`I thought that was only possible in Chinese fantasy novels.`,TWN:`我還以為這招只能武俠小說中看到，沒想到現實中也存在啊。`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L22_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`그거, 수류탄을 반으로 갈라서 불발시킨 사람 입에서 나올 법한 대사는 아니지 않아요?`,JPN:`それ、手榴弾を真っ二つに切り裂いて不発にした人が言う台詞ではないですよね？`,ENG:`That doesn't sound right, coming from someone who can disarm grenades by cutting them in half.`,TWN:`呃，這應該不是能將手榴彈一刀兩斷的人該說的台詞吧？`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L24_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_SUMMER_NULL`,text:{KOREA:`상황이 진정된 듯 하니 정식으로 감사 인사를 드려야겠네요.`,JPN:`落ち着いたようですので、ちゃんとお礼を言わせていただきましょう。`,ENG:`Now that the situation is settled, let me thank you in a more formal capacity.`,TWN:`看來情況穩定下來了，我在這裡向大家正式地致謝。`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`PRESIDENT_SCHOOL_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};